  ('Mechanical Engineering', 42.0, 'Direct-to-College of Engineering admission preferred; capacity-constrained major; supplemental application after enrollment; strong math and physics coursework required; test-optional', 'QS #51-100 World (Mechanical Engineering)', 6.0, 76, NULL, NULL, 3.75, 'A*AA', 37, 97.0, 110, NULL),
  ('Electrical Engineering', 42.0, 'Direct-to-College of Engineering admission preferred; capacity-constrained major; supplemental application after enrollment; strong math and physics background required; test-optional', 'QS #51-100 World (Electrical & Electronic Engineering)', 6.0, 76, NULL, NULL, 3.75, 'A*AA', 37, 97.0, 110, NULL),
  ('Biology', 43.0, 'College of Arts & Sciences; minimum-requirement major with prerequisite courses in biology, chemistry, and math; test-optional', 'QS #51-100 World (Biological Sciences); THE #22 (Life Sciences)', 6.0, 76, NULL, NULL, 3.6, 'AAA', 35, 95.0, 110, NULL),
