  ('Informatics', 28.0, 'Capacity-constrained; direct-to-major or standard admission to the Information School; supplemental application with essays; test-optional', 'QS #23 World (Library & Information Management)', 6.0, 76, NULL, NULL, 3.7, 'AAA', 36, 96.0, 110, NULL),
